export function aStarGridShortestPath(grid: number[][], start: readonly [number, number], end: readonly [number, number]): number | null {
    const rows = grid.length;
    if (rows === 0) return null;
    const cols = grid[0].length;

    const sx = start[0], sy = start[1];
    const ex = end[0], ey = end[1];

    if (sx < 0 || sx >= cols || sy < 0 || sy >= rows || grid[sy][sx] === 1) return null;
    if (ex < 0 || ex >= cols || ey < 0 || ey >= rows || grid[ey][ex] === 1) return null;
    if (sx === ex && sy === ey) return 0;

    class MinHeap {
        data: any[] = [];
        push(item: any) {
            this.data.push(item);
            let i = this.data.length - 1;
            while (i > 0) {
                const p = (i - 1) >> 1;
                if (this.data[i].f < this.data[p].f) {
                    [this.data[i], this.data[p]] = [this.data[p], this.data[i]];
                    i = p;
                } else break;
            }
        }
        pop() {
            const top = this.data[0];
            const bottom = this.data.pop();
            if (this.data.length > 0) {
                this.data[0] = bottom;
                let i = 0;
                const n = this.data.length;
                while (true) {
                    let smallest = i;
                    const l = 2 * i + 1, r = 2 * i + 2;
                    if (l < n && this.data[l].f < this.data[smallest].f) smallest = l;
                    if (r < n && this.data[r].f < this.data[smallest].f) smallest = r;
                    if (smallest !== i) {
                        [this.data[i], this.data[smallest]] = [this.data[smallest], this.data[i]];
                        i = smallest;
                    } else break;
                }
            }
            return top;
        }
        get size() { return this.data.length; }
    }

    const heap = new MinHeap();
    const gScores = new Array(rows * cols).fill(Infinity);
    const startIdx = sy * cols + sx;
    gScores[startIdx] = 0;

    const hStart = Math.abs(ex - sx) + Math.abs(ey - sy);
    heap.push({ x: sx, y: sy, f: hStart, g: 0 });

    const dirs = [[1, 0], [-1, 0], [0, 1], [0, -1]];

    while (heap.size > 0) {
        const current = heap.pop();
        const cx = current.x, cy = current.y;
        const idx = cy * cols + cx;

        if (current.g > gScores[idx]) continue;
        if (cx === ex && cy === ey) return current.g;

        for (const [dx, dy] of dirs) {
            const nx = cx + dx, ny = cy + dy;
            if (nx < 0 || nx >= cols || ny < 0 || ny >= rows || grid[ny][nx] === 1) continue;

            const nIdx = ny * cols + nx;
            const tentativeG = current.g + 1;
            if (tentativeG < gScores[nIdx]) {
                gScores[nIdx] = tentativeG;
                const nh = Math.abs(ex - nx) + Math.abs(ey - ny);
                heap.push({ x: nx, y: ny, f: tentativeG + nh, g: tentativeG });
            }
        }
    }

    return null;
}

