export function aStarGridShortestPath(grid: number[][], start: readonly [number, number], end: readonly [number, number]): number | null {
    const rows = grid.length;
    if (rows === 0) return null;
    const cols = grid[0].length;

    const sx = start[0], sy = start[1];
    const ex = end[0], ey = end[1];

    if (sx < 0 || sx >= cols || sy < 0 || sy >= rows || grid[sy][sx] === 1) return null;
    if (ex < 0 || ex >= cols || ey < 0 || ey >= rows || grid[ey][ex] === 1) return null;
    if (sx === ex && sy === ey) return 0;

    // Min-heap implementation for A*
    class MinHeap {
        private data: any[] = [];
        push(item: any) { this.data.push(item); this._bubbleUp(this.data.length - 1); }
        pop() {
            const top = this.data[0];
            const bottom = this.data.pop();
            if (this.data.length > 0) {
                this.data[0] = bottom;
                this._sinkDown(0);
            }
            return top;
        }
        get size() { return this.data.length; }
        private _bubbleUp(i: number) {
            while (i > 0) {
                const parent = (i - 1) >> 1;
                if (this.data[i].f < this.data[parent].f) {
                    [this.data[i], this.data[parent]] = [this.data[parent], this.data[i]];
                    i = parent;
                } else break;
            }
        }
        private _sinkDown(i: number) {
            const n = this.data.length;
            while (true) {
                let smallest = i;
                const left = 2 * i + 1;
                const right = 2 * i + 2;
                if (left < n && this.data[left].f < this.data[smallest].f) smallest = left;
                if (right < n && this.data[right].f < this.data[smallest].f) smallest = right;
                if (smallest !== i) {
                    [this.data[i], this.data[smallest]] = [this.data[smallest], this.data[i]];
                    i = smallest;
                } else break;
            }
        }
    }

    const heap = new MinHeap();
    // g scores map: "x,y" -> cost
    const gScores = new Map<string, number>();
    const startKey = `${sx},${sy}`;
    gScores.set(startKey, 0);

    const h = Math.abs(ex - sx) + Math.abs(ey - sy);
    heap.push({ x: sx, y: sy, f: h, g: 0 });

    const dirs = [[1, 0], [-1, 0], [0, 1], [0, -1]];

    while (heap.size > 0) {
        const current = heap.pop();
        const cx = current.x, cy = current.y;
        const key = `${cx},${cy}`;

        if (cx === ex && cy === ey) return current.g;

        const currentG = gScores.get(key)!;
        // If we already found a better path to this node, skip
        if (currentG < current.f - Math.abs(ex - cx) - Math.abs(ey - cy)) continue; 
        // Actually, standard A* checks if current.g > gScores.get(key). 
        // Since f = g + h, and h is fixed for a cell, we can just check g.
        // Let's simplify: store g in the heap node, and check against gScores.

        for (const [dx, dy] of dirs) {
            const nx = cx + dx, ny = cy + dy;
            if (nx < 0 || nx >= cols || ny < 0 || ny >= rows || grid[ny][nx] === 1) continue;

            const nKey = `${nx},${ny}`;
            const tentativeG = currentG + 1;
            const existingG = gScores.get(nKey);

            if (existingG === undefined || tentativeG < existingG) {
                gScores.set(nKey, tentativeG);
                const nh = Math.abs(ex - nx) + Math.abs(ey - ny);
                heap.push({ x: nx, y: ny, f: tentativeG + nh, g: tentativeG });
            }
        }
    }

    return null;
}
