function findTsFiles(dir: string): string[] {
  const files: string[] = [];
  if (!fs.existsSync(dir)) return files;
  const entries = fs.readdirSync(dir, { withFileTypes: true });
  for (const entry of entries) {
    const fullPath = path.join(dir, entry.name);
    if (entry.isDirectory()) {
      files.push(...findTsFiles(fullPath));
    } else if (entry.isFile() && entry.name.endsWith('.ts')) {
      files.push(fullPath);
    }
  }
  return files;
}

function parseImports(filePath: string): string[] {
  const content = fs.readFileSync(filePath, 'utf-8');
  const imports: string[] = [];
  const importRegex = /import\s+(?:[\w{},\s]+)\s+from\s+['"]([^'"]+)['"]/g;
  let match;
  while ((match = importRegex.exec(content)) !== null) {
    const importPath = match[1];
    if (importPath.startsWith('.')) {
      const resolved = path.resolve(path.dirname(filePath), importPath);
      if (fs.existsSync(resolved + '.ts')) {
        imports.push(resolved + '.ts');
      } else if (fs.existsSync(path.join(resolved, 'index.ts'))) {
        imports.push(path.join(resolved, 'index.ts'));
      }
    }
  }
  return imports;
}

export function detectCycles(rootDir: string): string[][] {
  const tsFiles = findTsFiles(rootDir);
  const adjList: Map<string, Set<string>> = new Map();

  for (const file of tsFiles) {
    if (!adjList.has(file)) {
      adjList.set(file, new Set());
    }
    const imports = parseImports(file);
    for (const imp of imports) {
      if (adjList.has(imp)) {
        adjList.get(file)?.add(imp);
      }
    }
  }

  const cycles: string[][] = [];
  const visited = new Set<string>();
  const recStack = new Set<string>();
  const pathStack: string[] = [];

  function dfs(node: string) {
    visited.add(node);
    recStack.add(node);
    pathStack.push(node);

    const neighbors = adjList.get(node);
    if (neighbors) {
      for (const neighbor of neighbors) {
        if (!visited.has(neighbor)) {
          dfs(neighbor);
        } else if (recStack.has(neighbor)) {
          const cycleStart = pathStack.indexOf(neighbor);
          const cycle = pathStack.slice(cycleStart);
          cycles.push([...cycle]);
        }
      }
    }

    pathStack.pop();
    recStack.delete(node);
  }

  for (const file of tsFiles) {
    if (!visited.has(file)) {
      dfs(file);
    }
  }

  return cycles;
}

